    34→type ConversionRate = {
    35→  label: string;
    36→  value: number;
    37→  total: number;
    38→};
    39→
    40→function calcPercent(value: number, total: number): string {
    41→  if (total === 0) return '0%';
    42→  return `${Math.round((value / total) * 100)}%`;
    43→}
