    58→        <span className={highlight ? 'text-primary' : 'text-muted-foreground'}>{icon}</span>
    59→      </div>
    60→      <div className={`text-2xl font-bold ${highlight ? 'text-primary' : ''}`}>{value.toLocaleString('pt-BR')}</div>
    61→      {description && <p className="text-xs text-muted-foreground mt-1">{description}</p>}
    62→    </div>
    63→  );
    64→}
