    66→const FUNNEL_BAR_COLORS: string[] = [
    67→  '#CE4836', // coral — cor primária do sistema
    68→  '#D97706', // âmbar — análogo quente
    69→  '#4F46E5', // índigo — complementar frio
    70→  '#059669', // esmeralda — triádico
    71→];
    72→
    73→type FunnelBarProps = {
    74→  steps: ConversionRate[];
    75→};
    76→
    77→function FunnelBars({ steps }: FunnelBarProps) {
    78→  return (
