    85→      </div>
    86→      <div className="space-y-4">
    87→        {steps.map((step, index) => {
    88→          const barColor = FUNNEL_BAR_COLORS[index % FUNNEL_BAR_COLORS.length];
    89→          return (
    90→            <div key={step.label}>
    91→              <div className="flex items-center justify-between mb-1">
    92→                <span className="text-body text-muted-foreground flex items-center gap-2">
    93→                  <span
    94→                    aria-hidden="true"
    95→                    className="inline-block w-2.5 h-2.5 rounded-full flex-shrink-0"
    96→                    style={{ backgroundColor: barColor }}
    97→                  />
    98→                  {step.label}
    99→                </span>
   100→                <span className="text-body font-semibold">
   101→                  {step.value} / {step.total} ({calcPercent(step.value, step.total)})
   102→                </span>
   103→              </div>
   104→              <div className="w-full bg-secondary rounded-full h-2">
   105→                <div
   106→                  className="h-2 rounded-full transition-[width]"
