   109→                    width: step.total > 0 ? `${Math.round((step.value / step.total) * 100)}%` : '0%',
   110→                  }}
   111→                />
   112→              </div>
   113→            </div>
   114→          );
   115→        })}
   116→      </div>
   117→    </div>
   118→  );
